// Update aria-label only when the stream is complete
async function streamResponse(aiNode, stream) {
  let fullText = "";
  for await (const chunk of stream) {
    fullText += chunk;
    aiNode.textContent = fullText;      // live region reads this
  }
  // Set summary label once — reader does not re-announce
  const summary = fullText.slice(0, 200) + (fullText.length > 200 ? "…" : "");
  aiNode.setAttribute("aria-label", `AI response: ${summary}`);
}
